     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
     9→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    10→import type { NotificationChannel, ChannelInput } from "@/lib/api/types";
    11→
    12→const channelFields: Record<string, { label: string; placeholder: string }[]> = {
    13→  slack: [
    14→    { label: "Webhook URL", placeholder: "https://hooks.slack.com/services/..." },
    15→    { label: "Channel", placeholder: "#releases" },
    16→  ],
    17→  pagerduty: [
    18→    { label: "Routing Key", placeholder: "R0xxxxx" },
    19→  ],
    20→  webhook: [
    21→    { label: "URL", placeholder: "https://your-service.com/api/releases" },
    22→    { label: "Headers", placeholder: "Authorization: Bearer token" },
    23→  ],
    24→};
    25→
    26→interface ChannelFormProps {
    27→  initial?: NotificationChannel;
    28→  onSubmit: (input: ChannelInput) => Promise<void>;
    29→  title: string;
    30→}
    31→
    32→export function ChannelForm({ initial, onSubmit, title }: ChannelFormProps) {
    33→  const router = useRouter();
    34→  const [saving, setSaving] = useState(false);
    35→  const [error, setError] = useState("");
    36→  const [type, setType] = useState(initial?.type ?? "slack");
    37→  const [name, setName] = useState(initial?.name ?? "");
    38→  const [config, setConfig] = useState<Record<string, unknown>>(initial?.config ?? {});
    39→
    40→  const fields = channelFields[type] ?? [];
    41→
    42→  const handleConfigChange = (label: string, value: string) => {
    43→    const key = label.toLowerCase().replace(/ /g, "_");
    44→    setConfig((prev) => ({ ...prev, [key]: value }));
    45→  };
    46→
    47→  const handleSubmit = async (e: React.FormEvent) => {
    48→    e.preventDefault();
    49→    setError("");
    50→    setSaving(true);
    51→    try {
    52→      await onSubmit({ type, name, config });
    53→      router.push("/channels");
    54→    } catch (err: unknown) {
    55→      setError(err instanceof Error ? err.message : "Failed to save");
    56→    } finally {
    57→      setSaving(false);
    58→    }
    59→  };
    60→
    61→  return (
    62→    <Card className="mx-auto max-w-2xl">
    63→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
    64→      <CardContent>
    65→        <form onSubmit={handleSubmit} className="space-y-4">
    66→          {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    67→          <div className="space-y-2">
    68→            <Label htmlFor="name">Name</Label>
    69→            <Input id="name" value={name} onChange={(e) => setName(e.target.value)} placeholder="e.g. Engineering Releases" required />
    70→          </div>
    71→          <div className="space-y-2">
    72→            <Label>Type</Label>
    73→            <Select value={type} onValueChange={(v) => { setType(v); setConfig({}); }}>
    74→              <SelectTrigger><SelectValue /></SelectTrigger>
    75→              <SelectContent>
    76→                <SelectItem value="slack">Slack</SelectItem>
    77→                <SelectItem value="pagerduty">PagerDuty</SelectItem>
    78→                <SelectItem value="webhook">Webhook</SelectItem>
    79→              </SelectContent>
    80→            </Select>
    81→          </div>
    82→          {fields.map((field) => {
    83→            const key = field.label.toLowerCase().replace(/ /g, "_");
    84→            return (
    85→              <div key={key} className="space-y-2">
    86→                <Label htmlFor={key}>{field.label}</Label>
    87→                <Input id={key} value={String(config[key] ?? "")} onChange={(e) => handleConfigChange(field.label, e.target.value)} placeholder={field.placeholder} />
    88→              </div>
    89→            );
    90→          })}
    91→          <div className="flex justify-end gap-2">
    92→            <Button type="button" variant="outline" onClick={() => router.back()}>Cancel</Button>
    93→            <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
    94→          </div>
    95→        </form>
    96→      </CardContent>
    97→    </Card>
    98→  );
    99→}
