     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Switch } from "@/components/ui/switch";
     9→import { Textarea } from "@/components/ui/textarea";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    12→import type { Source, SourceInput } from "@/lib/api/types";
    13→
    14→interface SourceFormProps {
    15→  initial?: Source;
    16→  projectId?: string;
    17→  onSubmit: (input: SourceInput) => Promise<void>;
    18→  title: string;
    19→  redirectTo?: string;
    20→}
    21→
    22→export function SourceForm({ initial, onSubmit, title, redirectTo }: SourceFormProps) {
    23→  const router = useRouter();
    24→  const [saving, setSaving] = useState(false);
    25→  const [error, setError] = useState("");
    26→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    27→  const [repository, setRepository] = useState(initial?.repository ?? "");
    28→  const [pollInterval, setPollInterval] = useState(String(initial?.poll_interval_seconds ?? 300));
    29→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    30→  const [configJson, setConfigJson] = useState(
    31→    JSON.stringify(initial?.config ?? {}, null, 2)
    32→  );
    33→
    34→  const handleSubmit = async (e: React.FormEvent) => {
    35→    e.preventDefault();
    36→    setError("");
    37→
    38→    let parsedConfig: Record<string, unknown> | undefined;
    39→    if (configJson.trim() && configJson.trim() !== "{}") {
    40→      try {
    41→        parsedConfig = JSON.parse(configJson);
    42→      } catch {
    43→        setError("Config must be valid JSON");
    44→        return;
    45→      }
    46→    }
    47→
    48→    setSaving(true);
    49→    try {
    50→      await onSubmit({
    51→        provider,
    52→        repository,
    53→        poll_interval_seconds: Number(pollInterval),
    54→        enabled,
    55→        config: parsedConfig,
    56→      });
    57→      router.push(redirectTo ?? "/sources");
    58→    } catch (err: unknown) {
    59→      setError(err instanceof Error ? err.message : "Failed to save");
    60→    } finally {
    61→      setSaving(false);
    62→    }
    63→  };
    64→
    65→  return (
    66→    <Card className="mx-auto max-w-2xl">
    67→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
    68→      <CardContent>
    69→        <form onSubmit={handleSubmit} className="space-y-4">
    70→          {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    71→          <div className="space-y-2">
    72→            <Label>Provider</Label>
    73→            <Select value={provider} onValueChange={setProvider}>
    74→              <SelectTrigger><SelectValue /></SelectTrigger>
    75→              <SelectContent>
    76→                <SelectItem value="dockerhub">Docker Hub</SelectItem>
    77→                <SelectItem value="github">GitHub</SelectItem>
    78→              </SelectContent>
    79→            </Select>
    80→          </div>
    81→          <div className="space-y-2">
    82→            <Label htmlFor="repository">Repository</Label>
    83→            <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
    84→          </div>
    85→          <div className="space-y-2">
    86→            <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
    87→            <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
    88→          </div>
    89→          <div className="space-y-2">
    90→            <Label htmlFor="config">Config (JSON, optional)</Label>
    91→            <Textarea
    92→              id="config"
    93→              value={configJson}
    94→              onChange={(e) => setConfigJson(e.target.value)}
    95→              rows={4}
    96→              className="font-mono text-sm"
    97→              placeholder="{}"
    98→            />
    99→          </div>
   100→          <div className="flex items-center gap-3">
   101→            <Switch checked={enabled} onCheckedChange={setEnabled} />
   102→            <Label>Enabled</Label>
   103→          </div>
   104→          <div className="flex justify-end gap-2">
   105→            <Button type="button" variant="outline" onClick={() => router.back()}>Cancel</Button>
   106→            <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   107→          </div>
   108→        </form>
   109→      </CardContent>
   110→    </Card>
   111→  );
   112→}
