     1→package api
     2→
     3→import (
     4→	"context"
     5→	"net/http"
     6→	"strings"
     7→
     8→	"github.com/sentioxyz/releaseguard/internal/models"
     9→)
    10→
    11→// ChannelsStore defines the persistence operations for notification channels.
    12→type ChannelsStore interface {
    13→	ListChannels(ctx context.Context, page, perPage int) ([]models.NotificationChannel, int, error)
    14→	CreateChannel(ctx context.Context, ch *models.NotificationChannel) error
    15→	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
    16→	UpdateChannel(ctx context.Context, id string, ch *models.NotificationChannel) error
    17→	DeleteChannel(ctx context.Context, id string) error
    18→}
    19→
    20→// ChannelsHandler implements HTTP handlers for the /channels resource.
    21→type ChannelsHandler struct {
    22→	store ChannelsStore
    23→}
    24→
    25→// NewChannelsHandler returns a new ChannelsHandler.
    26→func NewChannelsHandler(store ChannelsStore) *ChannelsHandler {
    27→	return &ChannelsHandler{store: store}
    28→}
    29→
    30→// List handles GET /channels — returns a paginated list of notification channels.
    31→func (h *ChannelsHandler) List(w http.ResponseWriter, r *http.Request) {
    32→	page, perPage := ParsePagination(r)
    33→	channels, total, err := h.store.ListChannels(r.Context(), page, perPage)
    34→	if err != nil {
    35→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list channels")
    36→		return
    37→	}
    38→	if channels == nil {
    39→		channels = []models.NotificationChannel{}
    40→	}
    41→	RespondList(w, r, http.StatusOK, channels, page, perPage, total)
    42→}
    43→
    44→// Create handles POST /channels — creates a new notification channel.
    45→func (h *ChannelsHandler) Create(w http.ResponseWriter, r *http.Request) {
    46→	var ch models.NotificationChannel
    47→	if err := DecodeJSON(r, &ch); err != nil {
    48→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    49→		return
    50→	}
