    12→
    13→// discordEmbedDescriptionLimit is Discord's maximum embed description length.
    14→const discordEmbedDescriptionLimit = 4096
    15→
    16→type discordConfig struct {
    17→	WebhookURL string `json:"webhook_url"`
    18→}
    19→
    20→// DiscordSender sends notifications as Discord webhook messages with embeds.
    21→type DiscordSender struct {
    22→	Client *http.Client
    23→}
    24→
    25→// discordPayload is the Discord webhook payload.
    26→type discordPayload struct {
    27→	Embeds []discordEmbed `json:"embeds"`
    28→}
    29→
    30→type discordEmbed struct {
    31→	Title       string              `json:"title"`
    32→	Description string              `json:"description"`
    33→	Color       int                 `json:"color"`
    34→	Fields      []discordEmbedField `json:"fields,omitempty"`
    35→}
    36→
    37→type discordEmbedField struct {
    38→	Name   string `json:"name"`
    39→	Value  string `json:"value"`
    40→	Inline bool   `json:"inline"`
    41→}
    42→
    43→func (s *DiscordSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
    44→	var cfg discordConfig
    45→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
    46→		return fmt.Errorf("parse discord config: %w", err)
    47→	}
    48→
    49→	description := msg.Body
    50→	if len(description) > discordEmbedDescriptionLimit {
    51→		description = description[:discordEmbedDescriptionLimit-3] + "..."
    52→	}
    53→
    54→	payload := discordPayload{
    55→		Embeds: []discordEmbed{
    56→			{
    57→				Title:       msg.Title,
    58→				Description: description,
    59→				Color:       0x5865F2, // Discord blurple
    60→				Fields: []discordEmbedField{
    61→					{Name: "Version", Value: msg.Version, Inline: true},
    62→				},
    63→			},
    64→		},
    65→	}
    66→
    67→	body, err := json.Marshal(payload)
    68→	if err != nil {
    69→		return fmt.Errorf("marshal discord payload: %w", err)
    70→	}
    71→
    72→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
    73→	if err != nil {
    74→		return fmt.Errorf("create request: %w", err)
    75→	}
    76→	req.Header.Set("Content-Type", "application/json")
    77→
    78→	client := s.Client
    79→	if client == nil {
    80→		client = http.DefaultClient
    81→	}
    82→
    83→	resp, err := client.Do(req)
    84→	if err != nil {
    85→		return fmt.Errorf("send discord notification: %w", err)
    86→	}
    87→	defer resp.Body.Close()
    88→
    89→	if resp.StatusCode >= 400 {
    90→		return fmt.Errorf("discord returned status %d", resp.StatusCode)
    91→	}
    92→	return nil
    93→}
    94→

